// Verbatim TS mirror of runner/rl_viz/tracing/gae.py.
// Because delta_t is lambda-independent, the GAE inspector recomputes A_t for any
// lambda the user drags, purely client-side (improvement #2).

export function gaeFromDeltas(
  deltas: number[],
  gamma: number,
  lam: number,
  dones?: boolean[],
): number[] {
  const T = deltas.length;
  const d = dones ?? new Array(T).fill(false);
  const adv = new Array(T).fill(0);
  let running = 0;
  for (let t = T - 1; t >= 0; t--) {
    const nonterminal = d[t] ? 0 : 1;
    running = deltas[t] + gamma * lam * nonterminal * running;
    adv[t] = running;
  }
  return adv;
}

export function returnsFromAdvantages(adv: number[], values: number[]): number[] {
  return adv.map((a, i) => a + values[i]);
}

export interface GaeStep {
  t: number;
  state_id: string;
  action: string;
  reward: number;
  value: number;
  value_next: number;
  delta: number;
  done: boolean;
}

// Recompute advantages + returns for a stored trajectory at an arbitrary lambda.
export function recomputeGae(steps: GaeStep[], gamma: number, lam: number) {
  const deltas = steps.map((s) => s.delta);
  const dones = steps.map((s) => s.done);
  const values = steps.map((s) => s.value);
  const advantages = gaeFromDeltas(deltas, gamma, lam, dones);
  const returns = returnsFromAdvantages(advantages, values);
  return { advantages, returns };
}
