// Live formula sandbox (improvement #5). Pure client-side arithmetic so users can
// edit inputs in the Update Inspector and watch the result recompute. Each
// function mirrors the exact code lines shown in formulas.json.

export interface QLearningInputs {
  reward: number;
  gamma: number;
  alpha: number;
  q_sa: number;
  bootstrap: number; // max_a' Q(s',a')  (Q-learning) | Q(s',a'_next) (SARSA)
}
export function computeQLearning({ reward, gamma, alpha, q_sa, bootstrap }: QLearningInputs) {
  const target = reward + gamma * bootstrap;
  const tdError = target - q_sa;
  const newValue = q_sa + alpha * tdError;
  return { target, tdError, newValue };
}

export interface BanditInputs {
  reward: number;
  q: number;
  stepSize: number; // alpha or 1/N(a)
}
export function computeBandit({ reward, q, stepSize }: BanditInputs) {
  const tdError = reward - q;
  return { tdError, newValue: q + stepSize * tdError };
}

export interface PpoInputs {
  ratio: number;
  advantage: number;
  epsilon: number;
}
export function computePpoClip({ ratio, advantage, epsilon }: PpoInputs) {
  const clippedRatio = Math.min(Math.max(ratio, 1 - epsilon), 1 + epsilon);
  const unclipped = ratio * advantage;
  const clipped = clippedRatio * advantage;
  const objective = Math.min(unclipped, clipped);
  const clipActive = ratio < 1 - epsilon || ratio > 1 + epsilon;
  // which branch the min() selected — for highlighting in the UI
  const selected: "unclipped" | "clipped" =
    unclipped <= clipped ? "unclipped" : "clipped";
  return { clippedRatio, unclipped, clipped, objective, clipActive, selected };
}

export function ratioFromLogprobs(logpNew: number, logpOld: number) {
  return Math.exp(logpNew - logpOld);
}

// Bellman backup expected value for one action: sum_s' p*(r + gamma*V(s')).
export interface BackupTerm {
  prob: number;
  reward: number;
  gamma_v: number; // gamma * V(s')
}
export function computeBackup(terms: BackupTerm[]) {
  return terms.reduce((acc, t) => acc + t.prob * (t.reward + t.gamma_v), 0);
}
