import { useEffect } from "react";
import { usePlayer } from "../store";

export function TimelinePlayer() {
  const { bundle, cursor, playing, speed, setCursor, step, setPlaying, setSpeed } =
    usePlayer();

  useEffect(() => {
    if (!playing || !bundle) return;
    const id = setInterval(() => {
      const s = usePlayer.getState();
      if (s.cursor >= s.bundle!.events.length - 1) {
        s.setPlaying(false);
      } else {
        s.step(1);
      }
    }, 1000 / speed);
    return () => clearInterval(id);
  }, [playing, speed, bundle]);

  if (!bundle) return null;
  const total = bundle.events.length;
  const ev: any = bundle.events[cursor];
  const loc =
    ev?.episode !== undefined
      ? `ep ${ev.episode}, step ${ev.episode_step}`
      : ev?.global_update !== undefined
        ? `update ${ev.global_update}`
        : ev?.sweep !== undefined
          ? `sweep ${ev.sweep}`
          : "";

  return (
    <div className="panel">
      <h3>Timeline</h3>
      <div className="controls" style={{ marginBottom: 8 }}>
        <button className="btn" onClick={() => setCursor(0)} title="Restart">
          ⏮
        </button>
        <button className="btn" onClick={() => step(-1)} disabled={cursor <= 0}>
          ◀ Back
        </button>
        <button className="btn primary" onClick={() => setPlaying(!playing)}>
          {playing ? "⏸ Pause" : "▶ Play"}
        </button>
        <button className="btn" onClick={() => step(1)} disabled={cursor >= total - 1}>
          Step ▶
        </button>
        <label className="field">
          speed
          <input
            type="range"
            min={1}
            max={60}
            value={speed}
            onChange={(e) => setSpeed(Number(e.target.value))}
          />
          {speed}/s
        </label>
        <span className="pill mono">
          event {cursor + 1}/{total}
        </span>
        {loc && <span className="pill">{loc}</span>}
        <span className="pill mono">{ev?.event_type}</span>
      </div>
      <input
        type="range"
        min={0}
        max={total - 1}
        value={cursor}
        onChange={(e) => setCursor(Number(e.target.value))}
        style={{ width: "100%" }}
      />
    </div>
  );
}
