// Action-probability bars, optionally showing before vs. after a policy update.
export function ProbabilityBars({
  before,
  after,
  highlight,
}: {
  before: Record<string, number>;
  after?: Record<string, number>;
  highlight?: string;
}) {
  const actions = Object.keys(before);
  return (
    <div>
      {actions.map((a) => {
        const b = before[a] ?? 0;
        const af = after?.[a];
        return (
          <div key={a} style={{ marginBottom: 8 }}>
            <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12 }}>
              <span className="mono" style={{ color: a === highlight ? "#58a6ff" : undefined }}>
                {a}
              </span>
              <span className="mono">
                {b.toFixed(3)}
                {af !== undefined && (
                  <>
                    {" → "}
                    <span className={af >= b ? "good" : "bad"}>{af.toFixed(3)}</span>
                  </>
                )}
              </span>
            </div>
            <div className="bar-track">
              <div className="bar-fill" style={{ width: `${b * 100}%` }} />
              {af !== undefined && (
                <div className="bar-fill after" style={{ width: `${af * 100}%`, height: 7, top: 9 }} />
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}
