// Renders a gridworld from a snapshot: value/Q heatmap + greedy policy arrows +
// start/goal/cliff markers, highlighting the state being updated this step.

interface GridSnap {
  layout: string[];
  start: number[];
  goal: number[] | null;
  cliffs: number[][];
  walls: number[][];
  action_names: string[];
  state_values?: Record<string, number>;
  q_table?: Record<string, Record<string, number>>;
  greedy_policy?: Record<string, string>;
}

const DIR: Record<string, [number, number]> = {
  up: [0, -1],
  down: [0, 1],
  right: [1, 0],
  left: [-1, 0],
};

function lerpColor(t: number) {
  // t in [0,1]: red (low) -> grey -> green (high)
  const clamp = Math.max(0, Math.min(1, t));
  const a = [248, 81, 73]; // bad
  const m = [40, 47, 58]; // mid panel
  const g = [63, 185, 80]; // good
  const mix = (x: number[], y: number[], u: number) =>
    x.map((v, i) => Math.round(v + (y[i] - v) * u));
  const c = clamp < 0.5 ? mix(a, m, clamp * 2) : mix(m, g, (clamp - 0.5) * 2);
  return `rgb(${c[0]},${c[1]},${c[2]})`;
}

export function GridWorldView({
  snap,
  highlight,
  cell = 64,
}: {
  snap: GridSnap;
  highlight?: string | null;
  cell?: number;
}) {
  const rows = snap.layout.length;
  const cols = snap.layout[0].length;
  const values: Record<string, number> = {};
  if (snap.state_values) Object.assign(values, snap.state_values);
  else if (snap.q_table)
    for (const [sid, qs] of Object.entries(snap.q_table))
      values[sid] = Math.max(...Object.values(qs));
  const vals = Object.values(values);
  const vMin = vals.length ? Math.min(...vals) : 0;
  const vMax = vals.length ? Math.max(...vals) : 1;

  const wallSet = new Set(snap.walls.map((w) => `${w[0]},${w[1]}`));
  const cliffSet = new Set(snap.cliffs.map((w) => `${w[0]},${w[1]}`));
  const W = cols * cell;
  const H = rows * cell;

  return (
    <svg width="100%" viewBox={`0 0 ${W} ${H}`} className="grid-svg" style={{ maxWidth: W }}>
      {Array.from({ length: rows }).flatMap((_, r) =>
        Array.from({ length: cols }).map((_, c) => {
          const sid = `r${r}c${c}`;
          const isWall = wallSet.has(`${r},${c}`);
          const isCliff = cliffSet.has(`${r},${c}`);
          const isGoal = snap.goal && snap.goal[0] === r && snap.goal[1] === c;
          const isStart = snap.start[0] === r && snap.start[1] === c;
          const x = c * cell,
            y = r * cell;
          const v = values[sid];
          let fill = "#0d1117";
          if (isWall) fill = "#0a0d12";
          else if (isCliff) fill = "#3a1414";
          else if (isGoal) fill = "#143a1c";
          else if (v !== undefined) fill = lerpColor((v - vMin) / (vMax - vMin || 1));
          const greedy = snap.greedy_policy?.[sid];
          const dir = greedy ? DIR[greedy] : null;
          const cx = x + cell / 2,
            cy = y + cell / 2;
          return (
            <g key={sid}>
              <rect
                x={x + 1}
                y={y + 1}
                width={cell - 2}
                height={cell - 2}
                fill={fill}
                stroke={highlight === sid ? "#58a6ff" : "#30363d"}
                strokeWidth={highlight === sid ? 3 : 1}
                rx={4}
              />
              {!isWall && v !== undefined && (
                <text x={cx} y={y + 14} fill="#e6edf3" fontSize={10} textAnchor="middle" className="mono">
                  {v.toFixed(2)}
                </text>
              )}
              {dir && !isWall && !isGoal && (
                <line
                  x1={cx}
                  y1={cy + 4}
                  x2={cx + dir[0] * cell * 0.28}
                  y2={cy + 4 + dir[1] * cell * 0.28}
                  stroke="#e6edf3"
                  strokeWidth={2}
                  markerEnd="url(#arrow)"
                />
              )}
              {(isStart || isGoal || isCliff) && (
                <text x={cx} y={y + cell - 8} fill="#9aa7b4" fontSize={11} textAnchor="middle">
                  {isGoal ? "GOAL" : isStart ? "start" : "cliff"}
                </text>
              )}
            </g>
          );
        }),
      )}
      <defs>
        <marker id="arrow" markerWidth="6" markerHeight="6" refX="4" refY="3" orient="auto">
          <path d="M0,0 L6,3 L0,6 Z" fill="#e6edf3" />
        </marker>
      </defs>
    </svg>
  );
}
