import { create } from "zustand";
import {
  flattenEoi,
  loadBundle,
  type TraceBundle,
} from "./trace/loaders";
import type { EoiEntry } from "./trace/schema";

interface PlayerState {
  baseUrl: string | null;
  bundle: TraceBundle | null;
  eoiFlat: EoiEntry[];
  loading: boolean;
  error: string | null;
  cursor: number; // index into bundle.events
  playing: boolean;
  speed: number; // events per second

  load: (baseUrl: string, startCursor?: number) => Promise<void>;
  setCursor: (i: number) => void;
  step: (delta: number) => void;
  setPlaying: (p: boolean) => void;
  setSpeed: (s: number) => void;
  jumpEoi: (dir: 1 | -1, type?: string) => void;
}

export const usePlayer = create<PlayerState>((set, get) => ({
  baseUrl: null,
  bundle: null,
  eoiFlat: [],
  loading: false,
  error: null,
  cursor: 0,
  playing: false,
  speed: 8,

  async load(baseUrl, startCursor = 0) {
    if (get().baseUrl === baseUrl && get().bundle) return;
    set({ loading: true, error: null, playing: false, baseUrl });
    try {
      const bundle = await loadBundle(baseUrl);
      const eoiFlat = flattenEoi(bundle.eoi);
      const cursor = Math.min(Math.max(startCursor, 0), Math.max(bundle.events.length - 1, 0));
      set({ bundle, eoiFlat, loading: false, cursor });
    } catch (e: any) {
      set({ loading: false, error: e?.message ?? String(e) });
    }
  },

  setCursor(i) {
    const b = get().bundle;
    if (!b) return;
    set({ cursor: Math.min(Math.max(i, 0), b.events.length - 1) });
  },

  step(delta) {
    get().setCursor(get().cursor + delta);
  },

  setPlaying(p) {
    set({ playing: p });
  },
  setSpeed(s) {
    set({ speed: s });
  },

  jumpEoi(dir, type) {
    const { eoiFlat, cursor } = get();
    const list = type ? eoiFlat.filter((e) => e.type === type) : eoiFlat;
    if (!list.length) return;
    let target: EoiEntry | undefined;
    if (dir === 1) target = list.find((e) => e.event_index > cursor);
    else target = [...list].reverse().find((e) => e.event_index < cursor);
    if (target) get().setCursor(target.event_index);
  },
}));
