import { usePlayer } from "../store";

const TYPE_LABEL: Record<string, string> = {
  argmax_flip: "policy arrow flip",
  policy_delta: "policy moved",
  clip_active: "PPO clip active",
  advantage_sign_change: "advantage flips sign",
  entropy_collapse: "entropy collapse",
  max_td_error: "largest TD error",
};

export function EOIJumpBar() {
  const { bundle, jumpEoi } = usePlayer();
  if (!bundle) return null;
  const counts = bundle.manifest.eoi_counts || {};
  const defs = bundle.manifest.eoi_definitions || {};
  const types = Object.keys(counts);
  if (!types.length) return null;

  return (
    <div className="panel">
      <h3>Events of interest — jump to the moment</h3>
      <div className="controls" style={{ marginBottom: 8 }}>
        <button className="btn" onClick={() => jumpEoi(-1)}>
          ⟸ prev change
        </button>
        <button className="btn primary" onClick={() => jumpEoi(1)}>
          next change ⟹
        </button>
        <span className="muted" style={{ fontSize: 12 }}>
          (across all types; deep-linkable per moment)
        </span>
      </div>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
        {types.map((t) => (
          <button
            key={t}
            className="btn"
            title={defs[t] || t}
            onClick={() => jumpEoi(1, t)}
          >
            {TYPE_LABEL[t] || t} <span className="pill mono">{counts[t]}</span>
          </button>
        ))}
      </div>
    </div>
  );
}
