import { useMemo, useState } from "react";
import { usePlayer } from "../store";
import { recomputeGae } from "../trace/gae";
import { Formula } from "./Formula";
import { getFormula } from "../trace/formulas";

export function GAEInspector() {
  const { bundle, cursor } = usePlayer();

  const gae = useMemo(() => {
    if (!bundle) return null;
    for (let i = Math.min(cursor, bundle.events.length - 1); i >= 0; i--) {
      const e: any = bundle.events[i];
      if (e.event_type === "gae_trajectory") return e;
    }
    // fall back to the first one so the panel is populated before the first update
    return (bundle.events as any[]).find((e) => e.event_type === "gae_trajectory") ?? null;
  }, [bundle, cursor]);

  const [lam, setLam] = useState<number | null>(null);
  if (!gae) return null;
  const effLam = lam ?? gae.lam;
  const { advantages } = recomputeGae(gae.steps, gae.gamma, effLam);
  const f = getFormula("gae");

  const W = 620, H = 150, P = 26;
  const T = gae.steps.length;
  const deltas = gae.steps.map((s: any) => s.delta);
  const all = [...deltas, ...advantages, ...gae.advantages];
  const lo = Math.min(...all, 0), hi = Math.max(...all, 0);
  const x = (t: number) => P + (t / Math.max(T - 1, 1)) * (W - 2 * P);
  const y = (v: number) => H - P - ((v - lo) / (hi - lo || 1)) * (H - 2 * P);
  const path = (arr: number[]) => arr.map((v, t) => `${x(t).toFixed(1)},${y(v).toFixed(1)}`).join(" ");

  return (
    <div className="panel">
      <h3>Advantage / GAE inspector — drag λ (bias ↔ variance)</h3>
      {f && <div style={{ marginBottom: 6 }}><Formula latex={f.latex} /></div>}
      <div className="controls" style={{ marginBottom: 8 }}>
        <label className="field" style={{ flex: 1 }}>
          λ = {effLam.toFixed(2)}
          <input type="range" min={0} max={1} step={0.01} value={effLam}
            onChange={(e) => setLam(Number(e.target.value))} style={{ flex: 1 }} />
        </label>
        <button className="btn" onClick={() => setLam(null)}>reset to trained λ={gae.lam}</button>
      </div>
      <div className="muted" style={{ fontSize: 12, marginBottom: 6 }}>
        δₜ (grey) is <strong>λ-independent</strong>. Âₜ at trained λ={gae.lam} (dim) vs. your λ (bright).
        λ=0 → Âₜ=δₜ (low variance, biased); λ=1 → MC return − V (high variance).
      </div>
      <svg width="100%" viewBox={`0 0 ${W} ${H}`} className="grid-svg">
        <line x1={P} y1={y(0)} x2={W - P} y2={y(0)} stroke="#30363d" />
        <polyline points={path(deltas)} fill="none" stroke="#9aa7b4" strokeWidth={1.2} strokeDasharray="3 3" />
        <polyline points={path(gae.advantages)} fill="none" stroke="#3fb95066" strokeWidth={1.5} />
        <polyline points={path(advantages)} fill="none" stroke="#58a6ff" strokeWidth={2} />
        <text x={P} y={12} fill="#9aa7b4" fontSize={10}>t=0</text>
        <text x={W - P} y={12} fill="#9aa7b4" fontSize={10} textAnchor="end">t={T - 1}</text>
      </svg>
      <div className="muted mono" style={{ fontSize: 11 }}>
        — — δₜ &nbsp; <span style={{ color: "#3fb950" }}>—</span> Âₜ(trained) &nbsp;
        <span style={{ color: "#58a6ff" }}>—</span> Âₜ(λ={effLam.toFixed(2)})
      </div>
    </div>
  );
}
