// Trace loaders: fetch + gunzip (fflate) + parse/validate. MVP loads a whole
// trace's events into memory (tabular traces are small); per-file lazy loading
// is a later optimization (see plan §8.5).
import { gunzipSync, strFromU8 } from "fflate";
import {
  EoiFile,
  Manifest,
  Metrics,
  parseEvent,
  type EoiEntry,
  type TraceEvent,
} from "./schema";

async function fetchJson(url: string): Promise<any> {
  const res = await fetch(url);
  if (!res.ok) throw new Error(`fetch ${url}: ${res.status}`);
  return res.json();
}

async function fetchGz(url: string): Promise<string> {
  const res = await fetch(url);
  if (!res.ok) throw new Error(`fetch ${url}: ${res.status}`);
  const buf = new Uint8Array(await res.arrayBuffer());
  // If the server already decoded gzip (Content-Encoding), bytes are plain text.
  try {
    return strFromU8(gunzipSync(buf));
  } catch {
    return strFromU8(buf);
  }
}

export interface SnapshotEntry {
  file: string;
  kind: string;
  global_step: number;
  at_event_index: number;
  data: any;
}

export interface TraceBundle {
  baseUrl: string;
  manifest: Manifest;
  metrics: Metrics;
  eoi: EoiFile | null;
  events: TraceEvent[];
  snapshots: SnapshotEntry[]; // sorted by at_event_index
}

// Latest snapshot whose at_event_index <= cursor (optionally of a given kind).
export function snapshotAt(
  bundle: TraceBundle,
  cursor: number,
  kind?: string,
): SnapshotEntry | null {
  let best: SnapshotEntry | null = null;
  for (const s of bundle.snapshots) {
    if (kind && s.kind !== kind) continue;
    if (s.at_event_index <= cursor) best = s;
    else break;
  }
  return best ?? bundle.snapshots.find((s) => !kind || s.kind === kind) ?? null;
}

export async function loadManifest(baseUrl: string): Promise<Manifest> {
  return Manifest.parse(await fetchJson(`${baseUrl}/manifest.json`));
}

export async function loadEvents(
  baseUrl: string,
  manifest: Manifest,
  validateSample = true,
): Promise<TraceEvent[]> {
  const events: TraceEvent[] = [];
  for (const file of manifest.event_files) {
    const text = await fetchGz(`${baseUrl}/${file}`);
    for (const line of text.split("\n")) {
      if (!line.trim()) continue;
      events.push(JSON.parse(line) as TraceEvent);
    }
  }
  if (validateSample && events.length) {
    parseEvent(events[0]); // sample-validate to catch schema drift
    parseEvent(events[events.length - 1]);
  }
  return events;
}

export async function loadEoi(
  baseUrl: string,
  manifest: Manifest,
): Promise<EoiFile | null> {
  if (!manifest.eoi_file) return null;
  return EoiFile.parse(await fetchJson(`${baseUrl}/${manifest.eoi_file}`));
}

export async function loadSnapshot(baseUrl: string, file: string): Promise<any> {
  return JSON.parse(await fetchGz(`${baseUrl}/${file}`));
}

async function loadSnapshots(
  baseUrl: string,
  manifest: Manifest,
): Promise<SnapshotEntry[]> {
  const entries = await Promise.all(
    manifest.snapshot_files.map(async (file) => {
      const data = await loadSnapshot(baseUrl, file);
      return {
        file,
        kind: data.kind,
        global_step: data.global_step,
        at_event_index: data.at_event_index ?? 0,
        data,
      } as SnapshotEntry;
    }),
  );
  return entries.sort((a, b) => a.at_event_index - b.at_event_index);
}

export async function loadBundle(baseUrl: string): Promise<TraceBundle> {
  const manifest = await loadManifest(baseUrl);
  const [metricsRaw, events, eoi, snapshots] = await Promise.all([
    fetchJson(`${baseUrl}/metrics.json`),
    loadEvents(baseUrl, manifest),
    loadEoi(baseUrl, manifest),
    loadSnapshots(baseUrl, manifest),
  ]);
  return {
    baseUrl,
    manifest,
    metrics: Metrics.parse(metricsRaw),
    eoi,
    events,
    snapshots,
  };
}

// All EOI entries flattened + sorted by event_index (for "jump to next/prev").
export function flattenEoi(eoi: EoiFile | null): EoiEntry[] {
  if (!eoi) return [];
  return Object.values(eoi.index)
    .flat()
    .sort((a, b) => a.event_index - b.event_index);
}

// ---- catalog (list of available runs) ----
export interface CatalogEntry {
  run_id: string;
  algo: string;
  env: string;
  seed: number;
  title?: string | null;
  path: string; // relative to the traces root
  hyperparams: Record<string, any>;
  n_events: number;
  eoi_counts: Record<string, number>;
}
export interface Catalog {
  generated_at?: string;
  runs: CatalogEntry[];
}

// Resolve a public asset path against the document base, so fetches work under
// any host sub-path and regardless of the HashRouter route.
export function assetUrl(rel: string): string {
  return new URL(rel, document.baseURI).href;
}

export async function loadCatalog(tracesRoot = "traces"): Promise<Catalog> {
  return (await fetchJson(assetUrl(`${tracesRoot}/catalog.json`))) as Catalog;
}
