// Bandit arms: true mean vs. current estimate, pull counts, highlight pulled arm.
export function BanditArms({
  trueMeans,
  qEstimates,
  counts,
  optimalArm,
  pulledArm,
}: {
  trueMeans: number[];
  qEstimates: number[];
  counts: number[];
  optimalArm: number;
  pulledArm?: number;
}) {
  const all = [...trueMeans, ...qEstimates];
  const lo = Math.min(...all, 0);
  const hi = Math.max(...all, 0);
  const span = hi - lo || 1;
  const pos = (v: number) => ((v - lo) / span) * 100;

  return (
    <div>
      {trueMeans.map((tm, a) => (
        <div key={a} style={{ marginBottom: 10 }}>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12 }}>
            <span className="mono">
              arm {a}
              {a === optimalArm && <span className="pill good" style={{ marginLeft: 6 }}>optimal</span>}
              {a === pulledArm && <span className="pill" style={{ marginLeft: 6, borderColor: "#58a6ff" }}>pulled</span>}
            </span>
            <span className="mono muted">
              Q̂={qEstimates[a].toFixed(2)} · μ={tm.toFixed(2)} · N={counts[a]}
            </span>
          </div>
          <div className="bar-track" style={{ height: 18 }}>
            {/* estimate */}
            <div className="bar-fill" style={{ width: `${pos(qEstimates[a])}%`, opacity: 0.9 }} />
            {/* true mean tick */}
            <div
              style={{
                position: "absolute",
                left: `${pos(tm)}%`,
                top: 0,
                bottom: 0,
                width: 2,
                background: "#3fb950",
              }}
              title={`true mean ${tm.toFixed(3)}`}
            />
          </div>
        </div>
      ))}
      <div className="muted" style={{ fontSize: 11, marginTop: 4 }}>
        bar = current estimate Q̂(a) · green tick = true mean μ(a)
      </div>
    </div>
  );
}
