// Zod mirror of runner/rl_viz/tracing/events.py + manifest.py (contract v0.1.0).
// Objects use .passthrough() for forward-compat; the manifest is validated on
// load, events are validated lazily (the loader can sample-check).
import { z } from "zod";

export const TRACE_SCHEMA_VERSION = "0.1.0";

const Selection = z
  .object({
    strategy: z.string(),
    epsilon: z.number().nullish(),
    c: z.number().nullish(),
    temperature: z.number().nullish(),
    is_exploration: z.boolean(),
    greedy_action: z.string().nullish(),
  })
  .passthrough();

export const BanditUpdateEvent = z
  .object({
    event_type: z.literal("bandit_update"),
    global_step: z.number(),
    arm: z.number(),
    arm_label: z.string().nullish(),
    reward: z.number(),
    selection: Selection,
    formula_id: z.string(),
    q_before_arm: z.number(),
    n_before_arm: z.number(),
    step_size: z.number(),
    td_error: z.number(),
    updated_value: z.number(),
    q_before: z.array(z.number()),
    q_after: z.array(z.number()),
    n_after: z.array(z.number()),
    optimal_arm: z.number(),
    is_optimal_pull: z.boolean(),
    regret_step: z.number(),
    cumulative_regret: z.number(),
    explanation: z.string(),
  })
  .passthrough();

const BackupCandidate = z
  .object({
    action: z.string(),
    expected_value: z.number(),
    terms: z.array(
      z
        .object({
          next_state_id: z.string(),
          prob: z.number(),
          reward: z.number(),
          gamma_v: z.number(),
        })
        .passthrough(),
    ),
  })
  .passthrough();

export const BellmanBackupEvent = z
  .object({
    event_type: z.enum(["vi_backup", "pi_eval", "pi_improve"]),
    sweep: z.number(),
    global_step: z.number(),
    state: z.array(z.number()),
    state_id: z.string(),
    gamma: z.number(),
    candidates: z.array(BackupCandidate),
    v_before: z.number(),
    v_after: z.number(),
    best_action: z.string(),
    policy_before: z.string().nullish(),
    policy_after: z.string().nullish(),
    delta: z.number(),
    formula_id: z.string(),
    explanation: z.string(),
  })
  .passthrough();

export const TabularQUpdateEvent = z
  .object({
    event_type: z.enum(["q_update", "sarsa_update"]),
    global_step: z.number(),
    episode: z.number(),
    episode_step: z.number(),
    state: z.array(z.number()),
    state_id: z.string(),
    action: z.string(),
    reward: z.number(),
    next_state: z.array(z.number()),
    next_state_id: z.string(),
    next_action: z.string().nullish(),
    done: z.boolean(),
    selection: Selection,
    formula_id: z.string(),
    alpha: z.number(),
    gamma: z.number(),
    q_sa_before: z.number(),
    q_next: z.record(z.number()),
    bootstrap_value: z.number(),
    bootstrap_kind: z.enum(["max", "on_policy"]),
    target: z.number(),
    td_error: z.number(),
    updated_value: z.number(),
    q_before: z.record(z.number()),
    q_after: z.record(z.number()),
    policy_before: z.string(),
    policy_after: z.string(),
    policy_changed: z.boolean(),
    explanation: z.string(),
  })
  .passthrough();

export const PGSampleContribEvent = z
  .object({
    event_type: z.literal("pg_sample_contribution"),
    attribution_level: z.literal("per_sample"),
    global_update: z.number(),
    epoch: z.number().nullish(),
    minibatch_index: z.number().nullish(),
    sample_id: z.number(),
    state_id: z.string(),
    action: z.string(),
    reward: z.number(),
    return_value: z.number().nullish(),
    value_before: z.number().nullish(),
    advantage: z.number(),
    advantage_source: z.enum([
      "gae",
      "mc_return_minus_baseline",
      "td_residual",
      "mc_return",
    ]),
    logprob_old: z.number().nullish(),
    logprob_new: z.number().nullish(),
    ratio: z.number().nullish(),
    clip_epsilon: z.number().nullish(),
    clipped_ratio: z.number().nullish(),
    unclipped_term: z.number(),
    clipped_term: z.number().nullish(),
    sample_loss: z.number(),
    clip_active: z.boolean().nullish(),
    formula_id: z.string(),
    explanation: z.string(),
  })
  .passthrough();

export const PolicyUpdateEvent = z
  .object({
    event_type: z.literal("policy_update"),
    attribution_level: z.literal("minibatch"),
    global_update: z.number(),
    state_id: z.string(),
    metrics: z.record(z.number().nullable()),
    constraints: z.record(z.union([z.number(), z.null()])),
    policy_before: z.record(z.number()),
    policy_after: z.record(z.number()),
    policy_delta_l1: z.number(),
    argmax_before: z.string(),
    argmax_after: z.string(),
    argmax_flip: z.boolean(),
    formula_id: z.string(),
    attribution_note: z.string(),
    explanation: z.string(),
  })
  .passthrough();

export const GAETrajectoryEvent = z
  .object({
    event_type: z.literal("gae_trajectory"),
    global_update: z.number(),
    episode: z.number(),
    gamma: z.number(),
    lam: z.number(),
    steps: z.array(
      z
        .object({
          t: z.number(),
          state_id: z.string(),
          action: z.string(),
          reward: z.number(),
          value: z.number(),
          value_next: z.number(),
          delta: z.number(),
          done: z.boolean(),
        })
        .passthrough(),
    ),
    advantages: z.array(z.number()),
    returns: z.array(z.number()),
    formula_id: z.string(),
    explanation: z.string(),
  })
  .passthrough();

// Dispatch by event_type (avoids discriminatedUnion's literal-only constraint,
// which trips on the shared vi_backup/pi_eval/pi_improve and q_update/sarsa_update).
const EVENT_SCHEMAS: Record<string, z.ZodTypeAny> = {
  bandit_update: BanditUpdateEvent,
  vi_backup: BellmanBackupEvent,
  pi_eval: BellmanBackupEvent,
  pi_improve: BellmanBackupEvent,
  q_update: TabularQUpdateEvent,
  sarsa_update: TabularQUpdateEvent,
  pg_sample_contribution: PGSampleContribEvent,
  policy_update: PolicyUpdateEvent,
  gae_trajectory: GAETrajectoryEvent,
};

export function parseEvent(d: any) {
  const s = EVENT_SCHEMAS[d?.event_type];
  if (!s) throw new Error(`unknown event_type: ${d?.event_type}`);
  return s.parse(d);
}

export type TraceEvent =
  | z.infer<typeof BanditUpdateEvent>
  | z.infer<typeof BellmanBackupEvent>
  | z.infer<typeof TabularQUpdateEvent>
  | z.infer<typeof PGSampleContribEvent>
  | z.infer<typeof PolicyUpdateEvent>
  | z.infer<typeof GAETrajectoryEvent>;

export const Determinism = z
  .object({
    mode: z.enum(["exact", "tolerance"]),
    backend: z.string(),
    tol: z.number().nullish(),
    note: z.string().nullish(),
    versions: z.record(z.string()),
  })
  .passthrough();

export const Manifest = z
  .object({
    run_id: z.string(),
    algo: z.string(),
    env: z.string(),
    seed: z.number(),
    created_at: z.string(),
    commit: z.string().nullish(),
    trace_schema_version: z.string(),
    determinism: Determinism,
    title: z.string().nullish(),
    notes: z.string().nullish(),
    hyperparams: z.record(z.any()),
    available_views: z.array(z.string()),
    event_files: z.array(z.string()),
    snapshot_files: z.array(z.string()),
    n_events: z.number(),
    metrics_summary: z.record(z.any()),
    eoi_definitions: z.record(z.string()),
    eoi_counts: z.record(z.number()),
    eoi_file: z.string().nullish(),
  })
  .passthrough();
export type Manifest = z.infer<typeof Manifest>;

export const EoiEntry = z
  .object({
    type: z.string(),
    global_step: z.number().nullish(),
    event_index: z.number(),
    file: z.string(),
    label: z.string(),
    magnitude: z.number().nullish(),
    deeplink: z.string(),
  })
  .passthrough();
export type EoiEntry = z.infer<typeof EoiEntry>;

export const EoiFile = z
  .object({
    definitions: z.record(z.string()),
    index: z.record(z.array(EoiEntry)),
  })
  .passthrough();
export type EoiFile = z.infer<typeof EoiFile>;

export const Metrics = z
  .object({
    records: z.array(z.record(z.number())),
    summary: z.record(z.any()),
  })
  .passthrough();
export type Metrics = z.infer<typeof Metrics>;
