import { useMemo, useState } from "react";
import { usePlayer } from "../store";

const COLORS = ["#58a6ff", "#3fb950", "#d29922", "#f85149", "#bc8cff", "#39c5cf"];

export function MetricsChart() {
  const { bundle, cursor } = usePlayer();
  const records = bundle?.metrics.records ?? [];
  const keys = useMemo(
    () => (records.length ? Object.keys(records[0]).filter((k) => k !== "step") : []),
    [records],
  );
  const [selected, setSelected] = useState<string[]>([]);
  const active = selected.length ? selected : keys.slice(0, 2);

  if (!bundle || !records.length) return null;

  const W = 620,
    H = 200,
    P = 30;
  const steps = records.map((r) => r.step);
  const xMin = Math.min(...steps),
    xMax = Math.max(...steps);
  const xScale = (x: number) => P + ((x - xMin) / (xMax - xMin || 1)) * (W - 2 * P);
  const progress = cursor / Math.max(bundle.events.length - 1, 1);
  const markerX = P + progress * (W - 2 * P);

  return (
    <div className="panel">
      <h3>Metrics over training</h3>
      <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 8 }}>
        {keys.map((k, i) => {
          const on = active.includes(k);
          return (
            <button
              key={k}
              className="btn"
              style={on ? { borderColor: COLORS[i % COLORS.length] } : { opacity: 0.6 }}
              onClick={() =>
                setSelected((s) =>
                  s.includes(k) ? s.filter((x) => x !== k) : [...(s.length ? s : active), k],
                )
              }
            >
              <span style={{ color: COLORS[i % COLORS.length] }}>●</span> {k}
            </button>
          );
        })}
      </div>
      <svg width="100%" viewBox={`0 0 ${W} ${H}`} className="grid-svg">
        <line x1={markerX} y1={5} x2={markerX} y2={H - P} stroke="#e6edf3" strokeDasharray="3 3" opacity={0.5} />
        {active.map((k) => {
          const i = keys.indexOf(k);
          const vals = records.map((r) => r[k]).filter((v) => v !== undefined);
          const yMin = Math.min(...vals),
            yMax = Math.max(...vals);
          const yScale = (y: number) =>
            H - P - ((y - yMin) / (yMax - yMin || 1)) * (H - 2 * P);
          const pts = records
            .map((r) => `${xScale(r.step).toFixed(1)},${yScale(r[k]).toFixed(1)}`)
            .join(" ");
          return (
            <polyline
              key={k}
              points={pts}
              fill="none"
              stroke={COLORS[i % COLORS.length]}
              strokeWidth={1.5}
            />
          );
        })}
        <text x={P} y={H - 8} fill="#9aa7b4" fontSize={10}>
          {xMin}
        </text>
        <text x={W - P} y={H - 8} fill="#9aa7b4" fontSize={10} textAnchor="end">
          {xMax}
        </text>
      </svg>
    </div>
  );
}
