import { useEffect, useState } from "react";
import { getFormula } from "../trace/formulas";
import { computeBandit, computePpoClip, computeQLearning } from "../trace/sandbox";
import { Formula } from "./Formula";
import { ProbabilityBars } from "./ProbabilityBars";

function Sub({ sym, val, label }: { sym: string; val: string | number; label?: string }) {
  return (
    <div className="subrow">
      <span>
        <span className="sym">{sym}</span>
        {label && <span className="muted" style={{ marginLeft: 8, fontSize: 12 }}>{label}</span>}
      </span>
      <span className="mono">{typeof val === "number" ? val.toFixed(4) : val}</span>
    </div>
  );
}

function CodeLines({ ids }: { ids?: string[] }) {
  if (!ids) return null;
  return (
    <>
      {ids.map((l, i) => (
        <div key={i} className="code-line">
          {l}
        </div>
      ))}
    </>
  );
}

function num(e: React.ChangeEvent<HTMLInputElement>) {
  return Number(e.target.value);
}

// ---- Q-learning / SARSA live sandbox (#5) ----
function QSandbox({ ev }: { ev: any }) {
  const [r, setR] = useState(ev.reward);
  const [gamma, setGamma] = useState(ev.gamma);
  const [alpha, setAlpha] = useState(ev.alpha);
  const [q, setQ] = useState(ev.q_sa_before);
  const [boot, setBoot] = useState(ev.bootstrap_value);
  useEffect(() => {
    setR(ev.reward); setGamma(ev.gamma); setAlpha(ev.alpha);
    setQ(ev.q_sa_before); setBoot(ev.bootstrap_value);
  }, [ev]);
  const { target, tdError, newValue } = computeQLearning({
    reward: r, gamma, alpha, q_sa: q, bootstrap: boot,
  });
  return (
    <div className="sandbox" style={{ marginTop: 10 }}>
      <strong>Try it yourself</strong>{" "}
      <span className="muted">— edit the inputs, watch the update recompute (pure client-side):</span>
      <div className="grid2" style={{ marginTop: 8 }}>
        <label className="field">r <input type="number" step="0.1" value={r} onChange={(e) => setR(num(e))} /></label>
        <label className="field">γ <input type="number" step="0.05" value={gamma} onChange={(e) => setGamma(num(e))} /></label>
        <label className="field">α <input type="number" step="0.05" value={alpha} onChange={(e) => setAlpha(num(e))} /></label>
        <label className="field">Q(s,a) <input type="number" step="0.1" value={q} onChange={(e) => setQ(num(e))} /></label>
        <label className="field">bootstrap <input type="number" step="0.1" value={boot} onChange={(e) => setBoot(num(e))} /></label>
      </div>
      <div style={{ marginTop: 8 }}>
        <Sub sym="target = r + γ·bootstrap" val={target} />
        <Sub sym="TD error = target − Q(s,a)" val={tdError} />
        <div style={{ marginTop: 4 }}>
          new Q = <span className="result-num">{newValue.toFixed(4)}</span>
        </div>
      </div>
    </div>
  );
}

// ---- PPO clip live sandbox (#5) ----
function PPOSandbox({ ev }: { ev: any }) {
  const [ratio, setRatio] = useState(ev.ratio ?? 1);
  const [adv, setAdv] = useState(ev.advantage);
  const [eps, setEps] = useState(ev.clip_epsilon ?? 0.2);
  useEffect(() => {
    setRatio(ev.ratio ?? 1); setAdv(ev.advantage); setEps(ev.clip_epsilon ?? 0.2);
  }, [ev]);
  const { clippedRatio, unclipped, clipped, objective, clipActive, selected } = computePpoClip({
    ratio, advantage: adv, epsilon: eps,
  });
  return (
    <div className="sandbox" style={{ marginTop: 10 }}>
      <strong>Drag the ratio</strong>{" "}
      <span className="muted">— see when min() switches to the clipped branch:</span>
      <div style={{ marginTop: 8 }}>
        <label className="field" style={{ width: "100%" }}>
          ratio rₜ = {ratio.toFixed(3)}
          <input type="range" min={0.2} max={2} step={0.01} value={ratio}
            onChange={(e) => setRatio(num(e))} style={{ flex: 1 }} />
        </label>
        <div className="grid2" style={{ marginTop: 6 }}>
          <label className="field">advantage A <input type="number" step="0.1" value={adv} onChange={(e) => setAdv(num(e))} /></label>
          <label className="field">ε <input type="number" step="0.05" value={eps} onChange={(e) => setEps(num(e))} /></label>
        </div>
      </div>
      <div style={{ marginTop: 8 }}>
        <Sub sym="clip range" val={`[${(1 - eps).toFixed(2)}, ${(1 + eps).toFixed(2)}]`} />
        <Sub sym="clipped ratio" val={clippedRatio} />
        <Sub sym="rₜ·A (unclipped)" val={unclipped} />
        <Sub sym="clip(rₜ)·A (clipped)" val={clipped} />
        <div style={{ marginTop: 4 }}>
          objective = min(…) = <span className="result-num">{objective.toFixed(4)}</span>{" "}
          <span className={selected === "clipped" ? "warn" : "good"}>
            ({selected} branch{clipActive ? ", clip ACTIVE" : ""})
          </span>
        </div>
      </div>
    </div>
  );
}

export function UpdateInspector({ ev }: { ev: any }) {
  if (!ev) return null;
  const f = getFormula(ev.formula_id);
  const et = ev.event_type;

  return (
    <div className="panel">
      <h3>Update Inspector</h3>
      {f && (
        <div style={{ marginBottom: 8 }}>
          <div className="muted" style={{ fontSize: 12, marginBottom: 4 }}>{f.name}</div>
          <Formula latex={f.latex} />
        </div>
      )}

      {(et === "q_update" || et === "sarsa_update") && (
        <>
          <Sub sym="s, a" val={`${ev.state_id}, ${ev.action}`} />
          <Sub sym="r" val={ev.reward} label="reward" />
          <Sub sym={ev.bootstrap_kind === "max" ? "max_a' Q(s',a')" : "Q(s',a')"} val={ev.bootstrap_value} label="bootstrap" />
          <Sub sym="γ" val={ev.gamma} /><Sub sym="α" val={ev.alpha} />
          <Sub sym="Q(s,a) before" val={ev.q_sa_before} />
          <Sub sym="target = r + γ·bootstrap" val={ev.target} />
          <Sub sym="TD error" val={ev.td_error} />
          <Sub sym="Q(s,a) after" val={ev.updated_value} />
          <div className="subrow">
            <span className="sym">policy at s</span>
            <span className="mono">
              {ev.policy_before}
              {ev.policy_changed ? <span className="warn"> → {ev.policy_after} (flipped!)</span> : " (unchanged)"}
            </span>
          </div>
          <CodeLines ids={f?.code_lines} />
          <p className="muted" style={{ fontSize: 13 }}>{ev.explanation}</p>
          <QSandbox ev={ev} />
        </>
      )}

      {et === "bandit_update" && <BanditBody ev={ev} f={f} />}

      {(et === "vi_backup" || et === "pi_eval" || et === "pi_improve") && (
        <BackupBody ev={ev} f={f} />
      )}

      {et === "pg_sample_contribution" && <SampleBody ev={ev} f={f} />}

      {et === "policy_update" && <PolicyUpdateBody ev={ev} f={f} />}

      {et === "gae_trajectory" && (
        <p className="muted">
          This is a GAE trajectory event — see the <strong>Advantage / GAE inspector</strong> panel
          below to drag λ and watch Âₜ recompute.
        </p>
      )}
    </div>
  );
}

function BanditBody({ ev, f }: { ev: any; f: any }) {
  const [r, setR] = useState(ev.reward);
  const [q, setQ] = useState(ev.q_before_arm);
  const [ss, setSs] = useState(ev.step_size);
  useEffect(() => { setR(ev.reward); setQ(ev.q_before_arm); setSs(ev.step_size); }, [ev]);
  const { tdError, newValue } = computeBandit({ reward: r, q, stepSize: ss });
  return (
    <>
      <Sub sym="arm" val={ev.arm_label ?? `arm ${ev.arm}`} />
      <Sub sym="r" val={ev.reward} label="reward" />
      <Sub sym="Q(a) before" val={ev.q_before_arm} />
      <Sub sym="step size" val={ev.step_size} label={ev.n_before_arm ? `1/N or α` : ""} />
      <Sub sym="TD error = r − Q(a)" val={ev.td_error} />
      <Sub sym="Q(a) after" val={ev.updated_value} />
      <CodeLines ids={f?.code_lines} />
      <p className="muted" style={{ fontSize: 13 }}>{ev.explanation}</p>
      <div className="sandbox" style={{ marginTop: 10 }}>
        <strong>Try it</strong>
        <div className="grid2" style={{ marginTop: 8 }}>
          <label className="field">r <input type="number" step="0.1" value={r} onChange={(e) => setR(num(e))} /></label>
          <label className="field">Q(a) <input type="number" step="0.1" value={q} onChange={(e) => setQ(num(e))} /></label>
          <label className="field">step <input type="number" step="0.05" value={ss} onChange={(e) => setSs(num(e))} /></label>
        </div>
        <div style={{ marginTop: 6 }}>
          TD={tdError.toFixed(4)} → new Q = <span className="result-num">{newValue.toFixed(4)}</span>
        </div>
      </div>
    </>
  );
}

function BackupBody({ ev, f }: { ev: any; f: any }) {
  return (
    <>
      <Sub sym="state" val={ev.state_id} />
      <Sub sym="γ" val={ev.gamma} />
      <table className="qtable" style={{ width: "100%", margin: "8px 0" }}>
        <thead>
          <tr><th>action</th><th>Σ p·(r+γV(s'))</th></tr>
        </thead>
        <tbody>
          {ev.candidates.map((c: any) => (
            <tr key={c.action} style={c.action === ev.best_action ? { background: "rgba(63,185,80,.15)" } : {}}>
              <td style={{ textAlign: "left" }}>{c.action}{c.action === ev.best_action ? " ★" : ""}</td>
              <td>{c.expected_value.toFixed(4)}</td>
            </tr>
          ))}
        </tbody>
      </table>
      <Sub sym="V(s) before" val={ev.v_before} />
      <Sub sym="V(s) after = max" val={ev.v_after} />
      {ev.policy_after && (
        <div className="subrow">
          <span className="sym">π(s)</span>
          <span className="mono">{ev.policy_before ?? "—"} → {ev.policy_after}</span>
        </div>
      )}
      <CodeLines ids={f?.code_lines} />
      <p className="muted" style={{ fontSize: 13 }}>{ev.explanation}</p>
    </>
  );
}

function SampleBody({ ev, f }: { ev: any; f: any }) {
  const isPPO = ev.ratio != null;
  return (
    <>
      <div className="callout info" style={{ marginBottom: 8 }}>
        <strong>Per-sample contribution</strong> — this is one sample's term in the loss
        ({ev.advantage_source}). It is <em>not</em> the cause of the whole new policy.
      </div>
      <Sub sym="state, action" val={`${ev.state_id}, ${ev.action}`} />
      <Sub sym="advantage Aₜ" val={ev.advantage} />
      {ev.return_value != null && <Sub sym="return Gₜ" val={ev.return_value} />}
      {ev.value_before != null && <Sub sym="V(s) baseline" val={ev.value_before} />}
      {isPPO && (
        <>
          <Sub sym="logπ_old" val={ev.logprob_old} /><Sub sym="logπ_new" val={ev.logprob_new} />
          <Sub sym="ratio rₜ" val={ev.ratio} />
          <Sub sym="clip ε" val={ev.clip_epsilon} />
          <Sub sym="clipped ratio" val={ev.clipped_ratio} />
          <Sub sym="rₜ·A" val={ev.unclipped_term} />
          <Sub sym="clip(rₜ)·A" val={ev.clipped_term} />
        </>
      )}
      <Sub sym="sample loss" val={ev.sample_loss} />
      {ev.clip_active != null && (
        <div className="subrow">
          <span className="sym">clip</span>
          <span className={ev.clip_active ? "warn" : "good"}>{ev.clip_active ? "ACTIVE (ratio outside band)" : "inactive"}</span>
        </div>
      )}
      <CodeLines ids={f?.code_lines} />
      <p className="muted" style={{ fontSize: 13 }}>{ev.explanation}</p>
      {isPPO && <PPOSandbox ev={ev} />}
    </>
  );
}

function PolicyUpdateBody({ ev, f }: { ev: any; f: any }) {
  const constraints = Object.entries(ev.constraints).filter(([, v]) => v != null);
  const metrics = Object.entries(ev.metrics).filter(([, v]) => v != null);
  return (
    <>
      <div className="callout" style={{ marginBottom: 10 }}>
        <strong>Minibatch result.</strong> {ev.attribution_note}
      </div>
      <div className="muted" style={{ fontSize: 12, marginBottom: 4 }}>
        policy at {ev.state_id}, before → after the whole update
        {ev.argmax_flip && <span className="warn"> (argmax flipped {ev.argmax_before}→{ev.argmax_after})</span>}
      </div>
      <ProbabilityBars before={ev.policy_before} after={ev.policy_after} highlight={ev.argmax_after} />
      <Sub sym="‖Δπ‖₁" val={ev.policy_delta_l1} />
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "0 16px", marginTop: 8 }}>
        <div>
          <div className="muted" style={{ fontSize: 12 }}>update metrics</div>
          {metrics.map(([k, v]) => <Sub key={k} sym={k} val={v as number} />)}
        </div>
        <div>
          <div className="muted" style={{ fontSize: 12 }}>step-size limiters (not just clip!)</div>
          {constraints.map(([k, v]) => <Sub key={k} sym={k} val={v as number} />)}
        </div>
      </div>
      <p className="muted" style={{ fontSize: 13, marginTop: 6 }}>{ev.explanation}</p>
    </>
  );
}
