import type { CatalogEntry } from "../trace/loaders";

export function TraceSelector({
  runs,
  selected,
  onSelect,
}: {
  runs: CatalogEntry[];
  selected: string;
  onSelect: (path: string) => void;
}) {
  if (runs.length <= 1) return null;
  const label = (r: CatalogEntry) => {
    const hp = Object.entries(r.hyperparams)
      .filter(([k]) => ["alpha", "clip_epsilon", "epsilon", "strategy", "lr", "gamma", "env"].includes(k))
      .map(([k, v]) => `${k}=${v}`)
      .join(", ");
    return `${r.env}${hp ? " · " + hp : ""} · seed ${r.seed}`;
  };
  return (
    <label className="field">
      run / preset
      <select value={selected} onChange={(e) => onSelect(e.target.value)}>
        {runs.map((r) => (
          <option key={r.path} value={r.path}>
            {label(r)}
          </option>
        ))}
      </select>
    </label>
  );
}
