import { useEffect, useMemo, useState } from "react";
import { useParams, useSearchParams } from "react-router-dom";
import { ALGO_BY_SLUG } from "../algoMeta";
import { usePlayer } from "../store";
import {
  assetUrl,
  loadCatalog,
  snapshotAt,
  type Catalog,
  type CatalogEntry,
} from "../trace/loaders";
import { BanditArms } from "../components/BanditArms";
import { EOIJumpBar } from "../components/EOIJumpBar";
import { GAEInspector } from "../components/GAEInspector";
import { GridWorldView } from "../components/GridWorldView";
import { MetricsChart } from "../components/MetricsChart";
import { ProbabilityBars } from "../components/ProbabilityBars";
import { TimelinePlayer } from "../components/TimelinePlayer";
import { TraceSelector } from "../components/TraceSelector";
import { UpdateInspector } from "../components/UpdateInspector";

let catalogCache: Catalog | null = null;
const SNAP_KIND: Record<string, string> = {
  q_learning: "q_table",
  sarsa: "q_table",
  value_iteration: "values",
  policy_iteration: "values",
  reinforce: "policy",
  actor_critic: "policy",
  ppo_mini: "policy",
  bandit: "bandit",
};

// Overlay the current event onto the aligned snapshot so the grid reflects this step.
function mergeGrid(snap: any, ev: any) {
  if (!snap || !ev) return snap;
  const g = JSON.parse(JSON.stringify(snap));
  if (ev.event_type === "q_update" || ev.event_type === "sarsa_update") {
    if (g.q_table) g.q_table[ev.state_id] = ev.q_after;
    if (g.greedy_policy) g.greedy_policy[ev.state_id] = ev.policy_after;
    if (g.state_values) g.state_values[ev.state_id] = Math.max(...Object.values(ev.q_after as Record<string, number>));
  } else if (ev.event_type === "vi_backup" || ev.event_type === "pi_eval" || ev.event_type === "pi_improve") {
    if (g.state_values) g.state_values[ev.state_id] = ev.v_after;
    if (g.greedy_policy && ev.best_action) g.greedy_policy[ev.state_id] = ev.best_action;
  }
  return g;
}

export function AlgoPage() {
  const { slug } = useParams();
  const meta = slug ? ALGO_BY_SLUG[slug] : undefined;
  const [runs, setRuns] = useState<CatalogEntry[]>([]);
  const [path, setPath] = useState<string>("");
  const [params] = useSearchParams();
  const { bundle, cursor, loading, error, load, setCursor } = usePlayer();

  // load catalog + pick a run for this algo
  useEffect(() => {
    if (!meta) return;
    let cancelled = false;
    (async () => {
      if (!catalogCache) catalogCache = await loadCatalog();
      if (cancelled) return;
      const matching = catalogCache.runs.filter((r) => r.algo === meta.algo);
      setRuns(matching);
      setPath(matching[0]?.path ?? "");
    })();
    return () => {
      cancelled = true;
    };
  }, [meta?.algo]);

  // load the selected trace bundle
  useEffect(() => {
    if (!path) return;
    const startStep = Number(params.get("step") ?? 0);
    load(assetUrl(`traces/${path}`), startStep);
  }, [path]);

  const ev: any = bundle?.events[cursor];
  const kind = meta ? (SNAP_KIND[meta.algo] ?? "q_table") : "q_table";
  const snap = bundle ? snapshotAt(bundle, cursor, kind)?.data : null;
  const gridSnap = useMemo(() => mergeGrid(snap, ev), [snap, ev]);

  if (!meta) return <div className="err">Unknown algorithm: {slug}</div>;

  const det = bundle?.manifest.determinism;
  const shareUrl = `${location.origin}${location.pathname}#/rl/${slug}?step=${cursor}`;

  return (
    <div>
      <div className="page-head" style={{ marginBottom: 12 }}>
        <h1>{meta.title}</h1>
        <p className="sub">{meta.subtitle}</p>
        <p className="blurb">{meta.blurb}</p>
      </div>

      <div className="panel">
        <div className="controls">
          <TraceSelector runs={runs} selected={path} onSelect={setPath} />
          {det && (
            <span className="pill" title={JSON.stringify(det.versions)}>
              determinism: {det.mode} · {det.backend}
              {det.versions?.numpy ? ` · numpy ${det.versions.numpy}` : ""}
            </span>
          )}
          {bundle && <span className="pill mono">{bundle.manifest.n_events} events</span>}
          <button
            className="btn"
            onClick={() => navigator.clipboard?.writeText(shareUrl)}
            title={shareUrl}
          >
            🔗 share this step
          </button>
        </div>
      </div>

      {loading && <div className="loading">loading trace…</div>}
      {error && <div className="err">Failed to load trace: {error}</div>}

      {bundle && (
        <>
          <div className="algo-grid">
            <div className="panel">
              <h3>{meta.env === "bandit" ? "Arms" : "Environment / Policy"}</h3>
              {meta.env === "bandit" && ev?.q_after ? (
                <BanditArms
                  trueMeans={snap?.true_means ?? ev.q_after.map(() => 0)}
                  qEstimates={ev.q_after}
                  counts={ev.n_after}
                  optimalArm={ev.optimal_arm}
                  pulledArm={ev.arm}
                />
              ) : gridSnap ? (
                <>
                  <GridWorldView snap={gridSnap} highlight={ev?.state_id} />
                  {meta.view === "policy_probs" && gridSnap.policy_probs && (
                    <div style={{ marginTop: 12 }}>
                      <div className="muted" style={{ fontSize: 12, marginBottom: 4 }}>
                        π(·|start) at this point in training
                      </div>
                      <ProbabilityBars
                        before={gridSnap.policy_probs[`r${gridSnap.start[0]}c${gridSnap.start[1]}`]}
                      />
                    </div>
                  )}
                </>
              ) : (
                <div className="muted">no snapshot</div>
              )}
            </div>

            <UpdateInspector ev={ev} />
          </div>

          <div className="full">
            <EOIJumpBar />
            {meta.formulaIds.includes("gae") && <GAEInspector />}
            <TimelinePlayer />
            <MetricsChart />
            <div className="panel">
              <h3>Common misconceptions</h3>
              <ul className="muted" style={{ fontSize: 13, lineHeight: 1.7 }}>
                {meta.misconceptions.map((m, i) => (
                  <li key={i}>{m}</li>
                ))}
              </ul>
            </div>
          </div>
        </>
      )}
    </div>
  );
}
