// Typed access to the formula registry exported from rl_viz.tracing.formulas.
import formulasJson from "./formulas.json";

export interface FormulaVariable {
  symbol: string;
  label: string;
}
export interface FormulaDef {
  id: string;
  name: string;
  latex: string;
  variables: FormulaVariable[];
  code_lines: string[];
}

export const FORMULAS = formulasJson as unknown as Record<string, FormulaDef>;

export function getFormula(id: string | undefined): FormulaDef | undefined {
  return id ? FORMULAS[id] : undefined;
}
